#!/usr/bin/env python3
"""Generate ixsimpl_amalg.c by concatenating all src/*.c files.

Headers are left as-is (include guards make repeated #include harmless).
The output is deterministic: sources are sorted alphabetically.
"""

import sys
from pathlib import Path

REPO = Path(__file__).resolve().parent.parent
SRC = REPO / "src"
OUT = REPO / "ixsimpl_amalg.c"

HEADER = """\
/* ixsimpl_amalg.c -- single-translation-unit build of ixsimpl.
 *
 * AUTO-GENERATED by scripts/amalgamate.py -- do not edit by hand.
 */
#define IXS_AMALGAMATED
"""


def main() -> int:
    sources = sorted(SRC.glob("*.c"))
    if not sources:
        print("error: no .c files found in src/", file=sys.stderr)
        return 1

    parts = [HEADER]
    for src in sources:
        parts.append(f"\n/* {'=' * 68} */\n")
        parts.append(f"/* {src.name:<66s} */\n")
        parts.append(f"/* {'=' * 68} */\n\n")
        parts.append(src.read_text())

    text = "".join(parts)

    if OUT.exists() and OUT.read_text() == text:
        return 0

    OUT.write_text(text)
    print(f"updated {OUT.relative_to(REPO)}", file=sys.stderr)
    return 1


if __name__ == "__main__":
    raise SystemExit(main())
